import { PSBT, TX } from '@/util/index.js'

import {
  create_unit_output,
  create_unit_rune_data,
  get_account_input,
  get_contract_input,
  get_vault_input,
  calc_issuance_tx_cost,
  create_vault_return,
  create_vault_fund_conn_out,
  create_vault_spend_out,
  create_vault_fund_conn_vin,
  create_vault_spend_vin,
  get_vault_return_data,
  create_change_out,
  get_estimated_spend_size
} from '@/module/vault/lib/index.js'

import {
  BaseUtxo,
  VaultBorrowRequest,
  VaultBorrowCtx,
  PSBTData,
  AccountProfile,
  VaultBorrowConfig,
  PriceQuote,
  ProtocolProfile,
  VaultProfile,
  VaultTxQuote,
  VaultFeeOptions
} from '@/types/index.js' 

import CONST  from '@/const.js'
import Schema from '@/schema/index.js'

/* Define the indexes for our transaction input/output types. */

const ACCT_VIN_IDX  = CONST.TXMAP.borrow.acct_tx.vin.acct
const CONN_OUT_IDX  = CONST.TXMAP.borrow.acct_tx.vout.conn
const UNIT_OUT_IDX  = CONST.TXMAP.borrow.acct_tx.vout.unit
const VAULT_VIN_IDX = CONST.TXMAP.borrow.vault_tx.vin.vault
const CONN_VIN_IDX  = CONST.TXMAP.borrow.vault_tx.vin.conn

/**
 * Create a context object for a Vault Borrow action.
 * 
 * @param account_ctx   AccountCtx object from the unit-bearing account.
 * @param contract_ctx  Context object from the on-chain contract.
 * @param exchange_data Price data provided by the oracle.
 * @param unit_output   User-provided details for receiving the unit.
 * @param vault_config  User-provided config for updating the vault.
 * @param vault_prevout Prevout object from the current vault utxo.
 * @returns A VaultBorrowCtx object.
 */
export function create_vault_borrow_ctx (
  acct_profile  : AccountProfile,
  price_quote   : PriceQuote,
  proto_profile : ProtocolProfile,
  vault_profile : VaultProfile,
  req_config    : VaultBorrowConfig
) : VaultBorrowCtx {
  return {
    ...req_config,
    ...get_account_input(acct_profile),
    ...get_contract_input(proto_profile),
    ...get_vault_input(vault_profile),
    vault_quote  : price_quote,
    vault_action : 'b'
  }
}

/**
 * Create the unit issuance PSBT for the vault borrow action.
 * 
 * @param vault_ctx  A VaultBorrowCtx object.
 * @param sats_utxos An array of utxos to include for funding.
 * @param tx_feerate The transaction feerate to use (in sats/vbyte).
 * @returns A base64-encoded partial bitcoin transaction.
 */
export function create_vault_borrow_psbt1 (
  vault_ctx  : VaultBorrowCtx,
  sats_utxos : BaseUtxo[]
) : string {
  // Unpack the vault context object.
  const { acct_utxo, borrow_amount, unit_rune_id, unit_address, unit_postage } = vault_ctx
  // Calculate the value for the vault funding output.
  const conn_value = calc_connector_value(vault_ctx, sats_utxos)
  // Create a PSBT template.
  const pdata = PSBT.create.psbt({ allowUnknownOutputs: true })
  // Add the unit account output.
  pdata.addOutput(PSBT.create.output(acct_utxo))
  // Add the vault connector output.
  pdata.addOutput(create_vault_fund_conn_out(vault_ctx, conn_value))
  // Add the unit issuance output.
  pdata.addOutput(create_unit_output(unit_address, unit_postage))
  // Add the runestone data for the OP_RETURN output.
  pdata.addOutput(create_unit_rune_data(unit_rune_id, borrow_amount, UNIT_OUT_IDX))
  // Add the unit account being spent as input.
  pdata.addInput(PSBT.create.input(acct_utxo))
  // Add the client utxos to use for funding.
  for (const utxo of sats_utxos) {
    pdata.addInput(PSBT.create.input(utxo))
  }
  // Return the PSBT for signing.
  return PSBT.encode(pdata)
}

/**
 * Create the vault update PSBT for the vault borrow action.
 *
 * @param vault_ctx  A VaultBorrowCtx object.
 * @param acct_psbt  A partial transaction for updating a unit account.
 * @param tx_feerate The transaction feerate to use (in sats/vbyte).
 * @returns A base64-encoded partial bitcoin transaction.
 */
export function create_vault_borrow_psbt2 (
  vault_ctx : VaultBorrowCtx,
  acct_psbt : PSBTData
) : string {
  // Parse the funding PSBT.
  const acct_pdata   = PSBT.parse(acct_psbt)
  // Extract the connector utxo.
  const conn_utxo    = PSBT.extract.utxo(acct_pdata, CONN_OUT_IDX)
  // Update the unit balance for the vault.
  const unit_balance = calc_unit_balance(vault_ctx)
  // Calculate the vault output amount.
  const vault_amount = calc_vault_amount(vault_ctx)
  // Calculate the change amount.
  const change_amt   = calc_change_amount(vault_ctx, conn_utxo.value)
  // Get the return data for the repo transaction.
  const return_data  = get_vault_return_data(vault_ctx, unit_balance)
  // Create a PSBT template.
  const pdata = PSBT.create.psbt({ allowUnknownOutputs: true })
  // Add the vault utxo output.
  pdata.addOutput(create_vault_spend_out(vault_ctx, unit_balance, vault_amount))
  // Add the wallet change output.
  if (change_amt > 0) {
    pdata.addOutput(create_change_out(vault_ctx, change_amt))
  }
  // Add the vault data output.
  pdata.addOutput(create_vault_return(return_data))
  // Add the vault connector input.
  pdata.addInput(create_vault_spend_vin(vault_ctx))
  // Add the vault connector input.
  pdata.addInput(create_vault_fund_conn_vin(vault_ctx, conn_utxo))
  // Return the data encoded in PSBT format.
  return PSBT.encode(pdata)
}

/**
 * Create a network request for the vault borrow action.
 * 
 * @param vault_ctx  A VaultBorrowCtx object.
 * @param issue_psbt A partial transaction that issues UNIT from an account.
 * @param issue_psbt A partial transaction that updated a user's vault.
 * @param tx_feerate The transaction feerate to use (in sats/vbyte).
 * @returns A VaultBorrowRequest object.
 */
export function create_vault_borrow_req (
  vault_ctx  : VaultBorrowCtx,
  issue_psbt : string,
  vault_psbt : string
) : VaultBorrowRequest {
  const issue_txhex = PSBT.get.txhex(issue_psbt)
  const issue_txid  = TX.get_txid(issue_txhex)
  const vault_txhex = PSBT.get.txhex(vault_psbt)
  const vault_txid  = TX.get_txid(vault_txhex)
  // Extract the funding inputs.
  const sats_inputs   = PSBT.extract.funding_vins(issue_psbt, { start_idx: ACCT_VIN_IDX + 1 })
  // Extract the vault connector input.
  const connect_input = PSBT.extract.script_vin(vault_psbt, CONN_VIN_IDX)
  // Extract the vault update input.
  const vault_input   = PSBT.extract.script_vin(vault_psbt, VAULT_VIN_IDX)
  // Define a schema for the request.
  const schema = Schema.vault.req.borrow_req
  // Return a request object.
  return schema.parse({ ...vault_ctx, sats_inputs, connect_input, issue_psbt, issue_txhex, issue_txid, vault_input, vault_psbt, vault_txhex, vault_txid })
}

function calc_connector_value (
  vault_config : VaultBorrowConfig,
  sats_utxos   : BaseUtxo[]
) {
  // Unpack the vault context object.
  const { unit_postage, tx_feerate } = vault_config
  // Tally the total amount of funding inputs.
  const fund_value = sats_utxos.reduce((prev, curr) => prev + curr.value, 0)
  // Calculate the tx fees for the account issuance transaction.
  const issue_cost = calc_issuance_tx_cost(sats_utxos, unit_postage, tx_feerate)
  // Calculate the value for the vault funding output.
  return fund_value - issue_cost
}

function calc_unit_balance (
  vault_ctx : VaultBorrowCtx
) : number {
  // Unpack the vault context object.
  const { borrow_amount, vault_balance } = vault_ctx
  return vault_balance + borrow_amount
}

function calc_vault_amount (
  vault_ctx : VaultBorrowCtx
) : number {
  // Unpack the vault context object.
  const { deposit_amount, vault_utxo } = vault_ctx
  return vault_utxo.value + deposit_amount
}

function calc_change_amount (
  vault_config : VaultBorrowConfig,
  conn_value   : number
) {
  const { deposit_amount, tx_feerate } = vault_config
  const tx_size  = CONST.TXSIZE.TX.VAULT_CONN
  const tx_cost  = tx_size * tx_feerate
  return conn_value - (deposit_amount + tx_cost)
}

/**
 * Calculate the total (in sats) required to
 * fund a borrow transaction.
 * 
 * @param vault_ctx  A VaultBorrowCtx object.
 * @param tx_feerate The transaction feerate to use (in sats/vbyte).
 * @returns An estimated cost of the transaction (in sats).
 */
export function get_vault_borrow_quote (
  vault_config : VaultBorrowConfig,
  fee_options? : VaultFeeOptions
) : VaultTxQuote {
  const { deposit_amount, tx_feerate, unit_postage } = vault_config
  const spend_size = get_estimated_spend_size(fee_options)
  const action_size = CONST.TXSIZE.ACTION.VAULT_BORROW + spend_size
  const total_size  = action_size + spend_size
  const tx_cost     = total_size * tx_feerate
  const total_cost  = deposit_amount + unit_postage + tx_cost
  return { tx_vsize: total_size, tx_cost, total_cost }
}

/**
 * Calculate the change amount (in sats) for a vault borrow action.
 * 
 * @param vault_config A VaultBorrowConfig object.
 * @param sats_utxos   An array of utxos to include for funding.
 * @returns The change amount (in sats).
 */
export function get_vault_borrow_change (
  vault_config : VaultBorrowConfig,
  sats_utxos   : BaseUtxo[]
) {
  const conn_value = calc_connector_value(vault_config, sats_utxos)
  return calc_change_amount(vault_config, conn_value)
}

export default {
  create_ctx   : create_vault_borrow_ctx,
  create_psbt1 : create_vault_borrow_psbt1,
  create_psbt2 : create_vault_borrow_psbt2,
  create_req   : create_vault_borrow_req,
  get_quote    : get_vault_borrow_quote,
  get_change   : get_vault_borrow_change
}
