

import { ProtocolProfile } from '@/types/index.js'
import fetch_api  from '../api/fetch.js'
import vault_api  from '../api/vault/index.js'

import type {
  SignPSBTEntry,
  WalletAccountRecord,
  WalletConfig,
  WalletConnectAPI
} from '../types/connect.js'

export class VaultWallet {

  private readonly _acct : WalletAccountRecord
  private readonly _conf : WalletConfig
  private readonly _conn : WalletConnectAPI
  private readonly _mctx : ProtocolProfile

  constructor (
    accounts  : WalletAccountRecord,
    proto_ctx : ProtocolProfile,
    connector : WalletConnectAPI,
    config    : WalletConfig
  ) {
    this._acct = accounts
    this._conf = config
    this._conn = connector
    this._mctx = proto_ctx
  }

  get acct () : WalletAccountRecord {
    return this._acct
  }

  get config () {
    return this._conf
  }

  get contract_id () {
    return this._mctx.master_id
  }

  get network () {
    return this.config.network
  }

  get conn () {
    return this._conn
  }

  get ctx () {
    return this._mctx
  }

  get fetch () {
    return fetch_api(this)
  }

  get sign () {
    return {
      batch : (this.conn.sign.batch !== undefined)
        ? this.conn.sign.batch(this)
        : batch_default(this),
      psbt  : this.conn.sign.psbt(this),
      utxos : this.conn.sign.utxos(this)
    }
  }

  get vault () {
    return vault_api(this)
  }
}

function batch_default (client : VaultWallet) {
  return async (psbts : SignPSBTEntry[]) => {
    const signed : string[] = []
    for (const [ psbt, manifest ] of psbts) {
      const signed_psbt = await client.sign.psbt(psbt, manifest)
      signed.push(signed_psbt)
    }
    return signed
  }
}
