import { Assert, round_to_fixed } from '@/util/index.js'
import { calc_collateral_ratio, calc_portion }  from '@/lib/calc.js'

import type { LiquidationTerms, VaultTerms } from '@/types/index.js'

import CONST from '@/const.js'

const FLOAT_PREC = CONST.FLOAT_PREC

/**
 * Get the adjusted unit price from the unit price and divisibility.
 *
 * @param coin_price - The coin price to adjust.
 * @param divisor?   - The divisor to use for adjustment.
 * @returns The adjusted coin price.
 */
export function get_adjusted_unit_price (
  coin_price : number,
  divisor    : number = 0
) : number {
  // If the divisibility is zero, return the coin price.
  if (divisor === 0) return coin_price
  // Calculate the divisibility factor.
  const adjusted_price = coin_price * (10 ** divisor)
  // Return the adjusted coin price.
  return round_to_fixed(adjusted_price, divisor)
}

export function calc_sats_balance (
  sats_balance : number,
  repo_portion : number = 1.0
) : number {
  // Calculate the sats balance.
  return calc_portion(sats_balance, repo_portion)
}

export function calc_unit_balance (
  unit_balance : number,
  repo_portion : number = 1.0
) : number {
  // Calculate the unit balance.
  return calc_portion(unit_balance, repo_portion)
}

/**
 * Calculate the tax rate to use for liquidation, based on the minimum liquidation threshold.
 *
 * @param liquid_terms - The liquidation terms for the protocol.
 * @returns The tax rate to use for liquidation.
 */
export function calc_liquid_tax_rate (
  liquid_terms : LiquidationTerms
) {
  // Define the tax rate from the liquidation terms.
  const { liquid_tax_rate, liquidation_thold } = liquid_terms
  // Return the tax rate multiplied by the minimum liquidation threshold.
  return round_to_fixed(liquidation_thold * liquid_tax_rate, FLOAT_PREC)
}

/**
 * Calculate the subsidy rate to use for liquidation, based on the subsidy multiplier.
 *
 * @param liquid_terms  - The liquidation terms for the protocol.
 * @param subsidy_multi - The subsidy multiplier to use for liquidation.
 * @returns The subsidy rate to use for liquidation.
 */
export function calc_subsidy_rate (
  liquid_terms  : LiquidationTerms,
  subsidy_multi : number
) {
  //
  const { liquid_tax_rate, subsidy_inc_rate } = liquid_terms
  // Calculate the subsidy rate.
  const subsidy_rate = round_to_fixed(subsidy_inc_rate * subsidy_multi, FLOAT_PREC)
  // Return the subsidy rate, ensuring it is at or below the liquid tax rate.
  return Math.min(subsidy_rate, liquid_tax_rate)
}

/**
 * Calculate the subsidy multiplier to use for liquidation, based on the collateral ratio.
 *
 * @param liquid_terms - The liquidation terms for the protocol.
 * @param coll_ratio   - The collateral ratio of the vault.
 * @returns The subsidy multiplier to use for liquidation.
 */
export function calc_subsidy_multiplier (
  liquid_terms : LiquidationTerms,
  coll_ratio   : number
) {
  // Define the subsidy increment threshold from the liquidation terms.
  const { subsidy_inc_thold } = liquid_terms
  // Assert the subsidy increment threshold is greater than one.
  Assert.ok(subsidy_inc_thold > 1, 'subsidy increment threshold must be greater than 100%')
  // Calculate the maximum number of steps.
  const max_steps = (subsidy_inc_thold - 1) * 100
  // If the ratio is equal or above the subsidy threshold, return zero
  if (coll_ratio >= subsidy_inc_thold) return 0
  // Calculate the multiplier as a step function between the ratio and threshold.
  let multi = Math.floor((subsidy_inc_thold - coll_ratio) * 100)
  // Ensure the multiplier is at or below the maximum number of steps.
  multi = Math.min(multi, max_steps)
  // Ensure the multiplier is at or above zero.
  multi = Math.max(multi, 0)
  // Return the subsidy multiplier.
  return multi
}

/**
 * Calculate the subsidy sats from the sats balance and the subsidy rate.
 *
 * @param sats_balance  - The amount of sats balance to use for the calculation.
 * @param subsidy_rate  - The subsidy rate to use for the calculation.
 * @param taxable_sats  - The amount of taxable sats to use for the calculation.
 * @returns The subsidy sats.
 */
export function calc_subsidy_sats (
  sats_balance  : number,
  subsidy_rate  : number,
  taxable_sats  : number
) {
  // Calculate the subsidy sats.
  const subsidy_sats = Math.floor(sats_balance * subsidy_rate)
  // Return the subsidy sats, ensuring it is at or below the taxable sats.
  return Math.min(subsidy_sats, taxable_sats)
}

/**
 * Calculate the reserve value in sats from the liquid sats and the reserve rate.
 *
 * @param liquid_terms - The liquidation terms for the protocol.
 * @param liquid_sats  - The amount of liquid sats to use for the calculation.
 * @param reserve_rate - The reserve rate to use for the calculation.
 * @returns The reserve value in sats.
 */
export function calc_reserve_sats (
  liquid_terms  : LiquidationTerms,
  tax_remaining : number,
) {
  // Define the minimum amount of sats required for spending.
  const min_sats_amt  = liquid_terms.reserve_sats_min
  // Return the amount of sats reserved, or zero if below the minimum.
  return (tax_remaining >= min_sats_amt) ? tax_remaining : 0
}

/**
 * Calculate the collateral deficit based on the post-subsidy collateral ratio.
 *
 * @param vault_terms    - The vault terms for the protocol.
 * @param post_sub_ratio - The post-subsidy collateral ratio.
 * @returns The collateral deficit.
 */
export function calc_collateral_deficit (
  vault_terms  : VaultTerms,
  coin_price   : number,
  sats_amount  : number,
  unit_balance : number
) {
  // Define the minimum collateral ratio.
  const min_ratio  = vault_terms.collateral_min
  // Calculate the current collateral ratio.
  const curr_ratio = calc_collateral_ratio(sats_amount, unit_balance, coin_price)
  // Assert the current collateral ratio is greater than or equal to the minimum collateral ratio.
  Assert.ok(min_ratio >= curr_ratio, 'current collateral ratio is greater than minimum collateral ratio')
  // Return the collateral deficit.
  return min_ratio - curr_ratio
}
