import { Buff }               from '@cmdcode/buff'
import { get_vsize }          from '@/lib/util.js'
import { parse_vault_return } from './rdata.js'
import { get_actual_spend_size } from './util.js'

import type { TxData } from '@scrow/tapscript'

import type {
  BaseUtxo,
  VaultTokenData,
} from '@/types/index.js'

import CONST from '@/const.js'
import TX    from '@/util/tx.js'

/**
 * Parse the relevant data from a vault transaction.
 */
export function parse_vault_tx (tx : string | TxData) {
  // Extract the vault utxo.
  const vault_utxo = TX.extract_utxo(tx, 0)
  // Extract the vault return.
  const vault_return = TX.extract_op_return(tx)
  // Parse the vault return data.
  const vault_data   = parse_vault_return(vault_return)
  // Return the extracted data.
  return { vault_data, vault_utxo }
}

/**
 * Calculate the vsize of a vault token.
 */
export function get_vault_token_vsize (token : VaultTokenData) {
  const str = JSON.stringify(token, null, 2)
  const bytes = Buff.str(str)
  return get_vsize(bytes)
}

/**
 * Calculate the max amount of UNIT that is
 * issuable against the client's vault.
 */
export function get_max_unit_issuable (
  min_cr_ratio : number,
  oracle_quote : number,
  unit_balance : number,
  vault_sats   : number
) : number {
  // Calculate the total collateral value in UNIT.
  const collateral_unit_value = (vault_sats / 100_000_000) * oracle_quote
  // Calculate the maximum allowable debt based on the collateral value
  const max_allowable_unit = collateral_unit_value / min_cr_ratio
  // Calculate the additional debt that can be issued
  const max_available_unit = max_allowable_unit - unit_balance
    // If additionalDebt is negative, no more debt can be issued
  return (max_available_unit > 0) ? max_available_unit : 0
}

/**
 * Calculate the fees for a UNIT issuance transaction.
 * @param fund_utxos : A list of funding inputs for the transaction.
 * @param postage    : The amount of postage to use for the transaction.
 * @param tx_feerate : The rate to use (in sats/vbyte) for fees.
 * @returns          : The amount (in sats) to use for transaction fees.
 */
export function calc_issuance_tx_cost (
  fund_utxos : BaseUtxo[],
  postage    : number,
  tx_feerate : number
) : number {
  const base_tx_size    = CONST.TXSIZE.TX.GUARD_ACCOUNT
  const txin_spend_size = get_actual_spend_size(fund_utxos)
  const total_tx_size   = base_tx_size + txin_spend_size
  return (postage + (total_tx_size * tx_feerate))
}

/**
 * Calculate the fees for a UNIT issuance transaction.
 * @param fund_utxos : A list of funding inputs for the transaction.
 * @param postage    : The amount of postage to use for the transaction.
 * @param tx_feerate : The rate to use (in sats/vbyte) for fees.
 * @returns          : The amount (in sats) to use for transaction fees.
 */
export function calc_liquidate_tx_cost (
  fund_utxos  : BaseUtxo[],
  tx_feerate  : number,
  vault_count : number
) : number {
  const base_tx_size     = CONST.TXSIZE.TX.VAULT_LIQUID
  const repo_vault_size  = CONST.TXSIZE.TXIO.LIQUID_VAULT
  const total_vault_size = repo_vault_size * vault_count
  const txin_spend_size  = get_actual_spend_size(fund_utxos)
  const total_tx_size    = base_tx_size + total_vault_size + txin_spend_size
  return total_tx_size * tx_feerate
}

