import { encodeRunestone } from '@ducat-unit/runestone'

const RUNE_ID_REGEX = /\d+:\d+/

export function transfer_runes (
  rune_id : string,
  amount  : number | bigint,
  output  : number
) {
  // Check if rune identifier is valid.
  if (!RUNE_ID_REGEX.test(rune_id)) {
    throw new Error('invalid rune id: ' + rune_id)
  }
  // Split the rune identifier into its parts.
  const [ block, idx ] = rune_id.split(':')
  // Construct the runestone.
  const runestone = encodeRunestone({
    edicts : [ {
      id     : { block: BigInt(block), tx: Number(idx) },
      amount : BigInt(amount),
      output
    } ]
  })
  // Return the runestone as a hex string.
  return runestone.encodedRunestone.toString('hex')
}
