import { transfer_runes } from '@/util/runes.js'

import type { PSBTBaseOutput } from '@/types/index.js'

import CONST from '@/const.js'
import PSBT  from '@/util/psbt.js'

/**
 * Verify that the repayment amount is less than the unit balance.
 * 
 * @param balance_amt  The amount of unit balance.
 * @param repay_amount The amount of units being repaid.
 * @returns The unit balance.
 */
export function get_unit_balance (
  balance_amt  : number,
  repay_amount : number,
) {
  const unit_balance = balance_amt - repay_amount
  if (unit_balance < 0) {
    throw new Error(`repay amount is greater than unit balance: ${balance_amt} < ${repay_amount}`)
  }
  return unit_balance
}

/**
 * Calculate the change amount for the unit.
 * 
 * @param input_amount The amount of unit inputs.
 * @param repay_amount The amount of units being repaid.
 * @returns The change amount for the unit.
 */
export function get_unit_change (
  input_amount : number,
  repay_amount : number
) {
  const change_amt = input_amount - repay_amount
  if (change_amt < 0) {
    throw new Error(`insufficient unit balance from inputs: ${input_amount} < ${repay_amount}`)
  }
  return change_amt
}

/**
 * Create a PSBT output that is configured as a UNIT issuance utxo.
 * @param data : A data object that configures the UNIT issuance.
 * @returns
 */
export function create_unit_output (
  unit_address : string,
  unit_postage : number
) : PSBTBaseOutput {
  return PSBT.create.payout(unit_postage, unit_address)
}

/**
 * Create a runestone that transfers UNIT to an transaction output.
 * 
 * @param rune_id     The rune ID of the UNIT.
 * @param unit_amount The amount of UNIT to transfer.
 * @param utxo_index  The index of the transaction output to transfer the UNIT to.
 * @returns A runestone that transfers UNIT to an transaction output.
 */
export function create_unit_rune_data (
  rune_id     : string,
  unit_amount : number,
  utxo_index  : number
) {
  const script = transfer_runes(rune_id, unit_amount, utxo_index)
  return { amount: CONST.BIGINT._0, script }
}
