import { Assert, round_to_fixed } from '@/util/index.js'

import {
  calc_subsidy_multiplier,
  calc_subsidy_rate,
  calc_reserve_sats,
  get_adjusted_unit_price,
  calc_subsidy_sats,
} from './calc.js'

import {
  calc_collateral_ratio,
  calc_portion,
} from '@/lib/calc.js'

import {
  parse_liquidation_terms,
  parse_vault_terms
} from '../util.js'

import {
  verify_return_balances,
  verify_repo_portion
} from './verify.js'

import type {
  LiquidationConfig,
  LiquidationQuote,
  LiquidVaultProfile,
  ProtocolProfile,
  TermsMap,
  VaultProfile
} from '@/types/index.js'

import CONST from '@/const.js'

const FLOAT_PREC = CONST.FLOAT_PREC

/**
 * Get the liquid profile for a given vault.
 *
 * @param proto_profile - The protocol profile.
 * @param liquid_vault  - The profile of the vault to liquidate.
 * @param thold_key     - The threshold key for liquidating the vault.
 * @param coin_price    - The coin price (BTC/USD).
 * @param repo_portion    - The portion of the vault to liquidate.
 * @returns The liquid profile.
 */
export function get_liquid_profile (
  proto_profile : ProtocolProfile,
  liquid_vault  : VaultProfile,
  thold_key     : string,
  coin_price    : number,
  repo_portion  : number = 1.0
) : LiquidVaultProfile {
  // Assert that the vault has a positive unit balance.
  Assert.ok(liquid_vault.rdata.unit_balance > 0,           'vault unit balance must be greater than zero')
  // Assert that the vault has a positive sats balance.
  Assert.ok(liquid_vault.utxo.value > CONST.MIN_VAULT_BAL, 'vault sats balance must be greater than minimum vault balance')
  // Verify the repo portion.
  verify_repo_portion(repo_portion)
  // Define the sats total.
  const sats_total = liquid_vault.utxo.value
  // Define the unit total.
  const unit_total = liquid_vault.rdata.unit_balance
  // Define the unit divisor.
  const unit_divisor = proto_profile.runes.unit.divisor
  // Define the liquidation quote config.
  const quote_config = { coin_price, repo_portion, sats_total, unit_total, unit_divisor }
  // Calculate the liquidation quote.
  const liquid_quote = get_liquidation_quote(proto_profile.terms, quote_config)
  // Calculate the return sats and unit.
  const return_sats = sats_total - liquid_quote.sats_balance
  const return_unit = unit_total - liquid_quote.unit_balance
  // Verify the return balances.
  verify_return_balances(repo_portion, return_sats, return_unit)
  // Return the liquid profile.
  return {
    ...liquid_vault,
    liquid_quote,
    repo_portion,
    return_sats,
    return_unit,
    thold_key
  }
}

/**
 * Get the liquidation quote for a given repossession amount and vault balance.
 *
 * @param liquid_terms  - The liquidation terms for the protocol.
 * @param liquid_config - The liquidation config object.
 * @returns The liquidation quote for the vault.
 */
export function get_liquidation_quote (
  proto_terms   : TermsMap,
  liquid_config : LiquidationConfig
) : LiquidationQuote {
  // Unpack the liquidation config object.
  const { coin_price, repo_portion = 1.0, unit_divisor = 0 } = liquid_config
  // Calculate the sats available.
  const sats_available   = liquid_config.sats_total - CONST.MIN_VAULT_BAL
  // Calculate the sats balance.
  const sats_balance     = calc_portion(sats_available, repo_portion)
  // Calculate the unit balance.
  const unit_balance     = calc_portion(liquid_config.unit_total, repo_portion)
  // Unpack the liquidation terms.
  const liquid_terms     = parse_liquidation_terms(proto_terms)
  // Unpack the vault terms.
  const vault_terms      = parse_vault_terms(proto_terms)
  // Define the minimum collateral ratio.
  const min_collateral   = vault_terms.collateral_min
  // Define the tax rate.
  const tax_rate         = liquid_terms.liquid_tax_rate
  // Get the adjusted coin price.
  const adj_price        = get_adjusted_unit_price(coin_price, unit_divisor)
  // Calculate the collateral ratio between the liquid sats and the unit balance.
  const vault_cr         = calc_collateral_ratio(sats_balance, unit_balance, adj_price)
  // Calculate the tax amount.
  const taxable_sats     = Math.round(sats_balance * tax_rate)
  // Calculate the subsidy multiplier.
  const subsidy_multi    = calc_subsidy_multiplier(liquid_terms, vault_cr)
  // Calculate the protocol subsidy rate.
  const subsidy_rate     = calc_subsidy_rate(liquid_terms, subsidy_multi)
  // Calculate the subsidy sats.
  const subsidy_sats     = calc_subsidy_sats(sats_balance, subsidy_rate, taxable_sats)
  // Calculate the tax remaining after the subsidy.
  const tax_remaining    = taxable_sats - subsidy_sats
  // Calculate the tax reserve value in sats.
  const reserve_sats     = calc_reserve_sats(liquid_terms, tax_remaining)
  // Calculate the total value in sats that should be awarded to the liquidator.
  const reward_sats      = sats_balance - reserve_sats
  // Calculate the reward ratio.
  const reward_cr        = calc_collateral_ratio(reward_sats, unit_balance, adj_price)
  // Calculate the collateral deficit ratio.
  const deficit_cr       = min_collateral - reward_cr
  // Calculate the collateral deficit in sats.
  const deficit_sats     = Math.ceil((deficit_cr / reward_cr) * reward_sats)
  // Calculate the liquid vault nav.
  const liquid_nav       = round_to_fixed(reward_cr - 1, FLOAT_PREC)
  // Calculate the repo margin rate.
  const profit_margin    = round_to_fixed(liquid_nav / deficit_cr, FLOAT_PREC)
  // Return the context object.
  return {
    coin_price,
    vault_cr,
    deficit_cr,
    deficit_sats,
    liquid_nav,
    profit_margin,
    reserve_sats,
    reward_cr,
    reward_sats,
    sats_balance,
    subsidy_multi,
    subsidy_rate,
    subsidy_sats,
    taxable_sats,
    unit_balance,
    unit_divisor
  }
}
