import { SocketSubscription, WebSocketClient } from '@/class/socket.js'

import unit_req_api  from '../api/unit/index.js'
import vault_req_api from '../api/vault/index.js'

import type {
  ChainNetwork,
  GuardianTopic,
  SubscriptionEventMap,
} from '@/types/index.js'

export class GuardianClient extends WebSocketClient {
  private readonly _network : ChainNetwork
  private readonly _pubkey  : string

  constructor (
    host_url : string,
    network  : ChainNetwork,
    pubkey   : string
  ) {
    super(host_url)

    this._network = network
    this._pubkey  = pubkey
  }

  get network () {
    return this._network
  }

  get pubkey () {
    return this._pubkey
  }

  get req () {
    return {
      unit  : unit_req_api(this),
      vault : vault_req_api(this)
    }
  }

  subscribe <T extends SubscriptionEventMap> (
    topic       : GuardianTopic,
    identifier ?: string
  ) : SocketSubscription<T> {
    return new SocketSubscription<T>(this, topic, identifier)
  }
}
