import { Buff }         from '@cmdcode/buff'
import { EventEmitter } from './emitter.js'
import { parse_error }  from '@/util/helpers.js'

import type {
  EventType,
  MessageConfig,
  MessageData,
  SocketEventMap,
  SubscriptionEventMap,
  SubscriptionHandler
} from '@/types/index.js'

import Schema from '@/schema/index.js'

const VERBOSE = process.env['VERBOSE'] === 'true'

export class WebSocketClient extends EventEmitter<SocketEventMap> {

  private readonly _url    : string
  private readonly _socket : WebSocket

  constructor (socket : string | WebSocket) {
    super()

    this._url = (typeof socket !== 'string')
      ? socket.url
      : socket

    this._socket = (typeof socket !== 'string')
      ? socket
      : new WebSocket(this._url)

    this._socket.addEventListener('open',  () => this.emit('ready', this))
    this._socket.addEventListener('close', () => this.emit('close', this))
    this._socket.addEventListener('error', () => this.emit('error', 'socket error'))

    this._socket.addEventListener('message', (event : MessageEvent) => {
      try {
        const msg = parse_message(event.data)
        this.emit('message', msg)
      } catch (err) {
        this.emit('bounced', [ parse_error(err), event.data ])
      }
    })
  }

  get ready () {
    return this._socket.OPEN === 1
  }

  get url () {
    return this._url
  }

  send (config : MessageConfig) : void {
    // Generate a random id if one is not provided.
    const id  = config.id ?? Buff.random(16).hex
    // Serialize the message payload.
    const env = serialize_message({ ...config, id })
    // Log the message if verbose mode is enabled.
    if (VERBOSE) console.log('[ websocket ] sending request:', env)
    // Send the message.
    this._socket.send(env)
  }
}

export class SocketSubscription <T extends SubscriptionEventMap> extends EventEmitter<T> {

  private readonly _client  : WebSocketClient
  private readonly _id      : string
  private readonly _topic   : string

  private _outbox  : MessageConfig | null = null

  constructor (
    client      : WebSocketClient,
    topic       : string,
    identifier ?: string
  ) {
    super()
    this._client = client
    this._id     = identifier ?? Buff.random(16).hex
    this._topic  = topic

    this._client.on('message', (msg) => {
      if (this._filter(msg)) this.emit('msg', msg)
    })
  }

  get client () {
    return this._client
  }

  get id () {
    return this._id
  }

  _filter (msg : MessageData) {
    return (
      msg.type  !== 'req'       && 
      msg.topic === this._topic && 
      msg.id    === this._id
    )
  }

  _resolve (timeout : number): Promise<T['res']> {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => reject('timeout'), timeout)
      this.within('msg', (msg) => {
        if (VERBOSE) console.log('[ subscription ] received message:', msg)
        switch (msg.type) {
          case 'res':
            clearTimeout(timer)
            resolve(msg.data)
            break
          case 'rej':
            clearTimeout(timer)
            reject(msg.data)
            break
        }
      }, timeout)
    })
  }

  _send () {
    if (this._outbox !== null) {
      this._client.send(this._outbox)
      this._outbox = null
    } else {
      throw new Error('no message in outbox')
    }
  }

  register (handler : SubscriptionHandler<T>) {
    this._client.on('message', (msg) => {
      if (this._filter(msg)) handler(this, msg)
    })
  }

  resolve (timeout : number = 5000) {
    const res = this._resolve(timeout)
    this._send()
    return res
  }

  send (data: any) {
    this._outbox = {
      id    : this._id,
      topic : this._topic,
      type  : 'req' as EventType,
      data
    }
  }
}

function serialize_message (msg : MessageData) : string {
  const { id, topic, type, data } = msg
  try {
    return JSON.stringify([ type, id, topic, data ])
  } catch {
    throw new Error('failed to serialize envelope:\n' + msg.toString())
  }
}

function parse_message (payload : any) : MessageData {
  // If payload is a binary object:
  if (typeof payload === 'object') {
    // Convert object to a string.
    payload = payload.text()
  }
  // Attempt to parse the JSON payload.
  try {
    // Parse the JSON string.
    payload = JSON.parse(payload)
      // Validate the JSON payload.
    const schema = Schema.ws.envelope
    // Parse the payload.
    const parsed = schema.parse(payload)
    // Extract the id, topic, and data from the parsed payload.
    const [ type, id, topic, data ] = parsed
    // Return the validated payload.
    return { id, type, topic, data }
  } catch {
    // Throw if the JSON is invalid.
    throw new Error('failed to parse envelope: ' + payload)
  }
}
