/**
 * Create a vault spend output for a transaction.
 */
export function create_vault_spend_out (
  vault_ctx : VaultBaseCtx,
  unit_bal  : number,
  vault_amt : number
) : PSBTBaseOutput {
  // Unpack the vault data.
  const { guard_pubkey, vault_quote, vault_pubkey } = vault_ctx
  // Get the hash-lock for the vault.
  const thold_hash = vault_quote.thold_hash
  // Return the vault output.
  return (unit_bal > 0)
    ? create_vault_locked_spend_out(guard_pubkey, thold_hash, vault_amt, vault_pubkey)
    : create_vault_cleared_spend_out(guard_pubkey, vault_amt, vault_pubkey)
}

/**
 * Create a reserve spend output for a transaction.
 */
export function create_reserve_spend_out (
  liquid_ctx : LiquidationCtx
) : PSBTBaseOutput {
  // Unpack the vault context.
  const { reserve_sats, reserve_pk } = liquid_ctx
  // Assert the change amount is above the dust limit.
  Assert.ok(reserve_sats > CONST.DUST_LIMIT, 'reserve amount is below dust limit')
  // Create the bitcoin script for the change output.
  const script = Buff.hex('5120' + reserve_pk)
  // Return the change output.
  return { amount: BigInt(reserve_sats), script }
}

/**
 * Create a change output for a transaction.
 */
export function create_change_out (
  vault_ctx  : VaultBaseCtx,
  change_amt : number
) : PSBTBaseOutput {
  const { sats_address } = vault_ctx
  // Assert the change amount is above the dust limit.
  Assert.ok(change_amt > CONST.DUST_LIMIT, 'change amount is below dust limit')
  // Create the bitcoin script for the change output.
  const script = TX.parse_address_script(sats_address)
  // Return the change output.
  return { amount: BigInt(change_amt), script }
}
