import type {
  ContractPointers,
  ValuePointer
} from '@/types/index.js'

export function get_contract_pointers (
  ctx : Partial<ContractPointers>
) : ValuePointer[] {
  const pointers : ValuePointer[] = []
  for (const key of Object.keys(ctx)) {
    const record = ctx[key as keyof ContractPointers]
    if (record !== undefined) {
      pointers.push(...record.ptr)
    }
  }
  return pointers
}
