/**
 *  A fully-typed implementation of an event emitter object.
 */

type EventKey <S extends EventMap> = string & keyof S
type EventMap   = Record<string, any>
type EventSet   = Set <Function>
type EventStore = Map <keyof EventMap, EventSet>

export class EventEmitter<S extends EventMap = {}> {
  private readonly _events : EventStore

  constructor () { this._events = new Map() }

  private _getHandlers = (event : string) : EventSet => {
    let events = this._events.get(event)
    if (events === undefined) {
      events = new Set()
      this._events.set(event, events)
    }
    return events
  }

  public has = (event : string) : boolean => {
    const res = this._events.get(event)
    return (res instanceof Set && res.size > 0)
  }

  public on = <K extends EventKey <S>> (
    event : K, fn : (payload : S[K]) => void | Promise<void>
  ) : void => {
    void this._getHandlers(event).add(fn)
  }

  public once = <K extends EventKey <S>> (
    event : K, fn : (payload : S[K]) => void | Promise<void>
  ) : void => {

    const onceFn = (payload : S[K]) : void => {
      this.remove(event, onceFn)
      void fn.apply(this, [ payload ])
    }

    this.on(event, onceFn)
  }

  public within = <K extends EventKey <S>> (
    event   : K,
    fn      : (payload : S[K]) => void | Promise<void>,
    timeout : number
  ) : void => {

    const withinFn = (payload : S[K]) : void => {
      void fn.apply(this, [ payload ])
    }

    setTimeout(() => { this.remove(event, withinFn) }, timeout)

    this.on(event, withinFn)
  }

  public emit = <K extends EventKey <S>> (
    event : K, payload ?: S[K] | null
  ) : void => {

    const methods : Function[] = []

    this._getHandlers(event).forEach((fn : Function) => {
      methods.push(fn.apply(this, [ payload ]))
    })

    this._getHandlers('*').forEach((fn : Function) => {
      methods.push(fn.apply(this, [ event, payload ]))
    })

    void Promise.allSettled(methods)
  }

  public remove = <K extends EventKey <S>> (
    event : K,
    fn : (payload : S[K]) => void
  ) : void => {

    this._getHandlers(event).delete(fn)
  }

  public clear = (event : string) : void => {
    this._events.delete(event)
  }
}
