export function calc_collateral_value (
  coll_ratio  : number,
  unit_amount : number,
  unit_rate   : number
) {
  const sats_amt = convert_unit_to_sats(unit_amount, unit_rate)
  return calc_portion(sats_amt, coll_ratio)
}
