import { fetch_account_profile } from './mint.js'
import { sleep }                 from '@/util/helpers.js'

import {
  fetch_outpoint_content,
  fetch_rand_outpoint
} from './ordx.js'

import type {
  AccountProfile,
  ApiResponse,
  ExchangeRecord,
  GuardianRecord,
  MintProfile
} from '@/types/index.js'

import CONST from '@/const.js'
import { Assert } from '@/util/index.js'

const { FETCH_IVAL, POSTAGE } = CONST

export async function fetch_rand_unit_account (
  mint    : MintProfile,
  esp_url : string,
  ord_url : string,
  address : string,
  ival    : number = FETCH_IVAL
) : Promise<ApiResponse<AccountProfile>> {
  const postage = POSTAGE.GET_TYPE('unit_account')
  Assert.exists(postage, 'unit account postage type not found')
  const res1    = await fetch_rand_outpoint(esp_url, address, postage)
  if (!res1.ok) return res1
  await sleep(ival)
  return fetch_account_profile(mint, ord_url, res1.data, ival)
}

export async function fetch_rand_guardian_host (
  esp_url : string,
  ord_url : string,
  address : string,
  ival    : number = FETCH_IVAL
) : Promise<ApiResponse<GuardianRecord>> {
  const postage = POSTAGE.GET_TYPE('guard_hosts')
  Assert.exists(postage, 'guard host postage type not found')
  const res1    = await fetch_rand_outpoint(esp_url, address, postage)
  if (!res1.ok) return res1
  await sleep(ival)
  return fetch_outpoint_content<GuardianRecord>(ord_url, res1.data, { ival })
}

