import { Assert }                  from '@/util/index.js'
import { parse_liquidation_terms } from '../util.js'
import { verify_batch_liquidate }  from './verify.js'

import type {
  LiquidationCtx,
  LiquidVaultProfile,
  ProtocolProfile
} from '@/types/index.js'

import CONST from '@/const.js'

/**
 * Get the liquidation context for a given set of vaults and unit price.
 *
 * @param liquid_vaults  - The array of liquid vaults.
 * @param proto_contract - The protocol contract.
 * @param unit_price     - The price of the unit / sats exchange.
 * @param options        - The liquidation options.
 * @returns The liquidation context for the vaults.
 */
export function get_liquidation_ctx (
  liquid_vaults  : LiquidVaultProfile[],
  proto_contract : ProtocolProfile
) : LiquidationCtx {
  // Assert that the vaults can be liquidated.
  verify_batch_liquidate(liquid_vaults)
  // Define the number of vaults being liquidated.
  const vault_count  = liquid_vaults.length
  // Define the liquidation terms.
  const liquid_terms = parse_liquidation_terms(proto_contract.terms)
  // Define the script public key for the reserve.
  const reserve_pk   = liquid_terms.reserve_pubkey
  // Calculate the total amount of liquid sats in the vaults.
  const total_sats   = get_liquid_sats_total(liquid_vaults)
  // Calculate the total amount of liquid units in the vaults.
  const total_unit   = get_liquid_unit_total(liquid_vaults)
  // Define the initial vault.
  const initial_vault = liquid_vaults.at(0)
  // Assert that the initial vault is defined.
  Assert.exists(initial_vault, 'no vaults to liquidate')
  // Define the amount of unit and sats to be returned from the initial vault.
  const return_unit = initial_vault.return_unit
  const return_sats = initial_vault.return_sats
  // Assert that remaining vaults are fully liquidated.
  Assert.ok(liquid_vaults.slice(1).every(vault => vault.repo_portion === 1), 'remaining vaults must be fully liquidated')
  // Initialize our working variables.
  let reserve_sats = 0,  // The amount of sats to be reserved for the protocol.
      claimed_sats = 0   // The amount of sats to be claimed by the liquidator.
  // For each liquid vault,
  for (let i = 0; i < vault_count; i++) {
    // Extract the vault from the array.
    const profile = liquid_vaults.at(i)
    // Assert that the vault is defined.
    Assert.exists(profile, 'vault is undefined')
    // Add the reserve and reward sats for the vault to the total.
    claimed_sats += profile.liquid_quote.reward_sats
    reserve_sats += profile.liquid_quote.reserve_sats
  }
  // Define the amount of unit that is being claimed.
  const claimed_unit = total_unit - return_unit
  // Return the liquidation context.
  return {
    liquid_terms,
    liquid_vaults,
    reserve_pk,
    reserve_sats,
    return_unit,
    return_sats,
    claimed_sats,
    claimed_unit,
    total_sats,
    total_unit,
    vault_count
  }
}

/**
 * Get the total amount of liquid sats in the vaults.
 *
 * @param liquid_vaults - The array of liquid vaults.
 * @returns The total amount of liquid sats in the vaults.
 */
export function get_liquid_sats_total (
  liquid_vaults : LiquidVaultProfile[]
) {
  return liquid_vaults.reduce((prev, curr) => {
    const value = curr.utxo.value - CONST.MIN_VAULT_BAL
    Assert.ok(value > 0, 'liquid vault value is less than minimum vault balance')
    return prev + value
  }, 0)
}

/**
 * Get the total amount of liquid units in the vaults.
 *
 * @param liquid_vaults - The array of liquid vaults.
 * @returns The total amount of liquid units in the vaults.
 */
export function get_liquid_unit_total (
  liquid_vaults : LiquidVaultProfile[]
) {
  return liquid_vaults.reduce((prev, curr) => prev + curr.rdata.unit_balance, 0)
}
