import { TX } from '@/util/index.js'

import {
  create_vault_return,
  create_vault_spend_out,
  create_vault_spend_vin,
  get_contract_input,
  get_vault_input,
  get_vault_return_data,
  create_change_out,
  get_estimated_spend_size,
  get_actual_spend_size
} from '@/module/vault/lib/index.js'

import {
  BaseUtxo,
  PriceQuote,
  ProtocolProfile,
  VaultDepositConfig,
  VaultDepositCtx,
  VaultDepositRequest,
  VaultFeeOptions,
  VaultProfile,
  VaultTxQuote
} from '@/types/index.js'

import CONST  from '@/const.js'
import PSBT   from '@/util/psbt.js'
import Schema from '@/schema/index.js'

/**
 * Define the indexes for our transaction input/output types.
 */
const VAULT_VIN_IDX = CONST.TXMAP.deposit.vault_tx.vin.vault

/**
 * Create a context object for a Vault Deposit action.
 * 
 * @param contract_ctx  Context object from the on-chain contract.
 * @param exchange_data Price data provided by the oracle.
 * @param vault_config  User-provided config for updating the vault.
 * @param vault_prevout Prevout object from the current vault utxo.
 * @param vault_pubkey  User-provided pubkey for updating the vault.
 * @returns A VaultDepositCtx object.
 */
export function create_vault_deposit_ctx (
  price_quote   : PriceQuote,
  proto_profile : ProtocolProfile,
  vault_profile : VaultProfile,
  req_config    : VaultDepositConfig
) : VaultDepositCtx {
  return {
    ...req_config,
    ...get_contract_input(proto_profile),
    ...get_vault_input(vault_profile),
    vault_quote  : price_quote,
    vault_action : 'd'
  }
}

/**
 * Create a vault deposit PSBT.
 */
export function create_vault_deposit_psbt (
  vault_ctx  : VaultDepositCtx,
  sats_utxos : BaseUtxo[]
) {
  // Unpack the vault context object.
  const { deposit_amount, vault_balance, vault_utxo } = vault_ctx
  // Calculate the vault output amount.
  const vault_amt  = vault_utxo.value + deposit_amount
  // Calculate the change amount to return to user.
  const change_amt = get_vault_deposit_change(vault_ctx, sats_utxos)
  // Get the return data for the repo transaction.
  const return_data = get_vault_return_data(vault_ctx, vault_balance)
  // Create a PSBT template.
  const pdata = PSBT.create.psbt({ allowUnknownOutputs: true })
  // Add the vault utxo output.
  pdata.addOutput(create_vault_spend_out(vault_ctx, vault_balance, vault_amt))
  // Add the wallet change output.
  if (change_amt > 0) {
    pdata.addOutput(create_change_out(vault_ctx, change_amt))
  }
  // Add the vault data output.
  pdata.addOutput(create_vault_return(return_data))
  // Add the vault update input.
  pdata.addInput(create_vault_spend_vin(vault_ctx))
  // Add the client utxos to use for funding.
  for (const utxo of sats_utxos) {
    pdata.addInput(PSBT.create.input(utxo))
  }
  // Return the data encoded in PSBT format.
  return PSBT.encode(pdata)
}

/**
 * Create a network request for the vault deposit action.
 */
export function create_vault_deposit_req (
  vault_ctx  : VaultDepositCtx,
  vault_psbt : string
) : VaultDepositRequest {
  const vault_txhex = PSBT.get.txhex(vault_psbt)
  const vault_txid  = TX.get_txid(vault_txhex)
  // Extract the funding inputs.
  const sats_inputs = PSBT.extract.funding_vins(vault_psbt, { start_idx: VAULT_VIN_IDX + 1 })
  // Extract the vault update input.
  const vault_input = PSBT.extract.script_vin(vault_psbt, VAULT_VIN_IDX)
  // Define a schema for the request.
  const schema = Schema.vault.req.deposit_req
  // Return a request object.
  return schema.parse({ ...vault_ctx, sats_inputs, vault_input, vault_psbt, vault_txhex, vault_txid })
}

/**
 * Calculate the total (in sats) required to
 * fund a deposit transaction.
 */
export function get_vault_deposit_quote (
  vault_config : VaultDepositConfig,
  fee_options  : VaultFeeOptions = {}
) : VaultTxQuote {
  const { deposit_amount, tx_feerate } = vault_config
  const spend_size = get_estimated_spend_size(fee_options)
  const tx_vsize   = CONST.TXSIZE.ACTION.VAULT_DEPOSIT + spend_size
  const tx_cost    = tx_vsize * tx_feerate
  const total_cost = deposit_amount + tx_cost
  return { tx_vsize, tx_cost, total_cost }
}

/**
 * Get the change amount (in sats) for a vault deposit action.
 */
function get_vault_deposit_change (
  vault_config : VaultDepositConfig,
  vin_utxos    : BaseUtxo[]
) {
  const { tx_feerate } = vault_config
  const vin_value  = vin_utxos.reduce((prev, curr) => prev + curr.value, 0)
  const vin_vsize  = get_actual_spend_size(vin_utxos)
  const tx_quote   = get_vault_deposit_quote(vault_config)
  const vin_cost   = vin_vsize * tx_feerate
  return vin_value - (vin_cost + tx_quote.total_cost)
}

export default {
  create_ctx  : create_vault_deposit_ctx,
  create_psbt : create_vault_deposit_psbt,
  create_req  : create_vault_deposit_req,
  get_quote   : get_vault_deposit_quote,
  get_change  : get_vault_deposit_change
}
