import type { PSBTManifest } from '../types/index.js'

/**
 * Create a manifest from a list of inputs.
 * 
 * @param inputs - The list of inputs to create the manifest from.
 * @returns The manifest.
 */
export function create_manifest (
  inputs : [ string, number[] ][]
) : PSBTManifest {
  // Create a manifest.
  const manifest : PSBTManifest = {}
  // Populate the manifest.
  for (const [ key, value ] of inputs) {
    // If the key is not in the manifest,
    if (manifest[key] === undefined) {
      // Add the key and empty array to the manifest.
      manifest[key] = []
    }
    // Add the value to the current key.
    manifest[key].push(...value)
  }
  // Return the manifest.
  return manifest
}
