import { VaultWallet } from '@/module/wallet/class/wallet.js'
import { Assert }      from '@/util/index.js'

import { create_manifest }          from '@/module/wallet/lib/util.js'
import { verify_vault_repo_config } from '@/module/wallet/lib/verify.js'

import { 
  verify_price_quote,
  verify_signed_utxo,
  verify_vault_profile 
} from '@/lib/verify.js'

import type {
  BaseUtxo,
  LiquidationCtx,
  PriceQuote,
  SignPSBTEntry,
  VaultProfile,
  VaultRepoConfig,
  VaultRepoCtx,
  WalletVaultRepoConfig,
  WalletVaultRepoRequest
} from '@/types/index.js'

import CONST    from '@/const.js'
import VaultAPI from '@/module/vault/index.js'

function vault_repo_ctx_api(client: VaultWallet) {
  return (
    price_quote   : PriceQuote,
    vault_profile : VaultProfile,
    vault_config  : WalletVaultRepoConfig
  ) : VaultRepoCtx => {
    verify_price_quote(price_quote)
    verify_vault_profile(vault_profile)
    verify_vault_repo_config(vault_config)

    const vault_pubkey = client.acct.vault.pubkey

    Assert.ok(vault_pubkey === vault_profile.vault_pk, 'incoming vault pubkey does not belong to wallet')

    const config: VaultRepoConfig = {
      ...vault_config,
      sats_address : client.acct.sats.address
    }

    return VaultAPI.repo.create_ctx(price_quote, client.ctx, vault_profile, config)
  }
}

function vault_repo_req_api(client: VaultWallet) {
  const vin_vault_idx = CONST.TXMAP.repo.vault_tx.vin.vault
  const vin_conn_idx  = CONST.TXMAP.repo.vault_tx.vin.conn

  return async (
    liquid_ctx : LiquidationCtx,
    vault_ctx  : VaultRepoCtx,
    utxos      : BaseUtxo[],
    batch      : boolean = false
  ): Promise<WalletVaultRepoRequest> => {
    // Unpack terms from client object.
    const { contract_id, network } = client
    // Define index of first funding input.
    const vin_fund_idx = liquid_ctx.liquid_vaults.length
    // Collect utxo input indexes.
    const utxo_inputs   = utxos.map((_, idx) => vin_fund_idx + idx)
    // Create psbt manifest.
    const utxo_manifest = create_manifest([
      [ client.acct.sats.address, utxo_inputs ]
    ])
    // Create vault signature manifest.
    const vault_manifest = create_manifest([
      [ client.acct.vault.address, [ vin_vault_idx, vin_conn_idx ] ]
    ])
    // Define psbt1 and psbt2.
    let psbt1: string, psbt2: string
    // If batching,
    if (batch) {
      // Create psbt1 and psbt2.
      psbt1 = VaultAPI.repo.create_psbt1(liquid_ctx, vault_ctx, utxos)
      psbt2 = VaultAPI.repo.create_psbt2(liquid_ctx, vault_ctx, psbt1)
      // Create a batch manifest.
      const batch_request = [ [ psbt1, utxo_manifest ], [ psbt2, vault_manifest ] ] as SignPSBTEntry[]
      // Request signatures for the batch.
      const signed_psbts  = await client.sign.batch(batch_request)
      // Unpack the signed psbts.
      psbt1 = signed_psbts[0]
      psbt2 = signed_psbts[1]
    } else {
      // Create psbt1.
      psbt1 = VaultAPI.repo.create_psbt1(liquid_ctx, vault_ctx, utxos)
      // Request signatures for psbt1.
      psbt1 = await client.sign.psbt(psbt1, utxo_manifest)
      // Create psbt2.
      psbt2 = VaultAPI.repo.create_psbt2(liquid_ctx, vault_ctx, psbt1)
      // Request signatures for psbt2.
      psbt2 = await client.sign.psbt(psbt2, vault_manifest)
    }
    // Create a repo request.
    const req = VaultAPI.repo.create_req(liquid_ctx, vault_ctx, psbt1, psbt2)
    // Verify the sats inputs.
    req.sats_inputs.forEach(verify_signed_utxo)
    // Return the request.
    return { ...req, contract_id, network }
  }
}

export default function(client: VaultWallet) {
  return {
    ctx         : vault_repo_ctx_api(client),
    liquidation : VaultAPI.repo.liquidation,
    quote       : VaultAPI.repo.get_tx_quote,
    req         : vault_repo_req_api(client)
  }
}
